function AuthForm() {
  const [strEmail, setStrEmail] = useState('');
  const [strPassword, setStrPassword] = useState('');
  const [bIsSubmitting, setBIsSubmitting] = useState(false);
  const [objError, setObjError] = useState(null);

  return (
    <form>
      <input value={strEmail} onChange={e => setStrEmail(e.target.value)} />
      <input value={strPassword} onChange={e => setStrPassword(e.target.value)} type="password" />
      {bIsSubmitting && <span>Logging in...</span>}
      {objError && <p>{objError.message}</p>}
    </form>
  );
}
